const today = new Date().toISOString().slice(0, 10);
const stamp = Date.now();
const runId = `N8N-STOCK-DN-${stamp}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, itemGroup: `${runId} Nhóm giao hàng`, warehouseName: `${runId} Delivery WH`, itemCode: `${runId} Hàng giao Đặc biệt`, customerName: `${runId} KH giao hàng`, receiptQty: 5, deliveryQty: 2, rate: 31 } }];

const ctx = $node['Build Delivery Context'].json;
const dn = $node['Submit Delivery Note'].json;
const bin = $('Verify Delivery Bin').all().map(i => i.json);
const sle = $('Verify Delivery SLE').all().map(i => i.json);
const text = JSON.stringify({ ctx, dn, bin, sle });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
const expectedQty = ctx.receiptQty - ctx.deliveryQty;
const status = Number(dn.docstatus) === 1 && Number(bin[0]?.actual_qty) === expectedQty && sle.some(row => Number(row.actual_qty) === -ctx.deliveryQty && Number(row.qty_after_transaction) === expectedQty) ? 'passed' : 'failed';
return [{ json: { status, runId: ctx.runId, customer: $node['Create Delivery Customer'].json.name, item: $node['Create Delivery Item'].json.name, warehouse: $node['Create Delivery Warehouse'].json.name, receipt: $node['Create Delivery Receipt'].json.name, deliveryNote: $node['Create Delivery Note'].json.name, deliveryNoteDocstatus: dn.docstatus, binActualQty: bin[0]?.actual_qty, deliveryLedgerRows: sle.length, deliveryLedgerActualQty: sle.map(row => row.actual_qty), deliveryLedgerQtyAfterTransaction: sle.map(row => row.qty_after_transaction), securityFindings } }];
